const data = $input.all();

if (data.length === 0) {
  return [{json: {html_table: "<p>No se encontraron datos para el reporte MODO.</p>"}}];
}

let html = '<h3 style="font-family: Arial, sans-serif; color: #333;">Reporte Mensual Consolidado: MODO</h3>';
html += '<table style="border-collapse: collapse; width: 100%; font-family: Arial, sans-serif; font-size: 13px;">';

// Headers
html += '<tr style="background-color: #003366; color: white; text-align: left;">';
html += '<th style="border: 1px solid #ddd; padding: 10px;">Mes</th>';
html += '<th style="border: 1px solid #ddd; padding: 10px;">Leads</th>';
html += '<th style="border: 1px solid #ddd; padding: 10px;">Visitas Agendadas</th>';
html += '<th style="border: 1px solid #ddd; padding: 10px;">Visitas Realizadas</th>';
html += '<th style="border: 1px solid #ddd; padding: 10px;">Nuevos Ingresos Depa</th>';
html += '<th style="border: 1px solid #ddd; padding: 10px;">Nuevos Ingresos Cochera</th>';
html += '</tr>';

// Rows
for (const item of data) {
    const row = item.json;

    let mesFormatted = '-';
    if (row.mes) {
        mesFormatted = row.mes.substring(0, 7); // Toma YYYY-MM
    }

    html += '<tr>';
    html += `<td style="border: 1px solid #ddd; padding: 8px; font-weight: bold;">${mesFormatted}</td>`;
    html += `<td style="border: 1px solid #ddd; padding: 8px; text-align: center;">${row.cant_leads_real || 0}</td>`;
    html += `<td style="border: 1px solid #ddd; padding: 8px; text-align: center;">${row.cant_visitas_agendadas_real || 0}</td>`;
    html += `<td style="border: 1px solid #ddd; padding: 8px; text-align: center;">${row.cant_visitas_realizadas || 0}</td>`;
    html += `<td style="border: 1px solid #ddd; padding: 8px; text-align: center; background-color: #f0f9ff;">${row.cant_nuevos_ingresos_depa_real || 0}</td>`;
    html += `<td style="border: 1px solid #ddd; padding: 8px; text-align: center; background-color: #f0f9ff;">${row.cant_nuevos_ingresos_cochera_real || 0}</td>`;
    html += '</tr>';
}

html += '</table>';

// Leyenda
html += '<br>';
html += '<table style="border-collapse: collapse; width: 100%; font-family: Arial, sans-serif; font-size: 12px; background-color: #f9f9f9;">';
html += '<tr style="background-color: #e8e8e8;"><th colspan="2" style="border: 1px solid #ccc; padding: 8px; text-align: left; color: #333;">Glosario de indicadores</th></tr>';
html += '<tr><td style="border: 1px solid #ccc; padding: 7px 10px; font-weight: bold; white-space: nowrap;">Leads</td><td style="border: 1px solid #ccc; padding: 7px 10px; color: #555;">Cantidad de personas interesadas en alquilar (envían un mensaje al WhatsApp de corretaje)</td></tr>';
html += '<tr><td style="border: 1px solid #ccc; padding: 7px 10px; font-weight: bold; white-space: nowrap;">Visitas agendadas</td><td style="border: 1px solid #ccc; padding: 7px 10px; color: #555;">Cantidad de personas que agendan una visita</td></tr>';
html += '<tr><td style="border: 1px solid #ccc; padding: 7px 10px; font-weight: bold; white-space: nowrap;">Visitas realizadas</td><td style="border: 1px solid #ccc; padding: 7px 10px; color: #555;">Cantidad de personas que realizan una visita</td></tr>';
html += '<tr><td style="border: 1px solid #ccc; padding: 7px 10px; font-weight: bold; white-space: nowrap;">Nuevos ingresos depa</td><td style="border: 1px solid #ccc; padding: 7px 10px; color: #555;">Cantidad de inmuebles registrados en el formulario de Nuevos Inquilinos del Intranet Rentas</td></tr>';
html += '<tr><td style="border: 1px solid #ccc; padding: 7px 10px; font-weight: bold; white-space: nowrap;">Nuevos ingresos cochera</td><td style="border: 1px solid #ccc; padding: 7px 10px; color: #555;">Cantidad de cocheras registradas en el formulario de Nuevos Inquilinos del Intranet Rentas</td></tr>';
html += '</table>';

html += `<p style="font-family: Arial; font-size: 11px; color: #666;">Este reporte incluye los últimos 180 días y se genera automáticamente el día 01 de cada mes.</p>`;

return [{json: {html_table: html}}];

